import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Cpu, Terminal, Lock } from 'lucide-react';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const { login, loading } = useAuth();
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    const toastId = toast.loading('INITIALIZING_SECURE_HANDSHAKE...');
    try {
      await login(email, password);
      toast.success('ACCESS_GRANTED', { id: toastId });
      navigate('/dashboard');
    } catch (error) {
      toast.error('GATE_REJECTION: INVALID_CREDENTIALS', { id: toastId });
    }
  };

  return (
    /* 🎯 FIX: flex items-center justify-center forces the card to the middle */
    <div className="min-h-[85vh] w-full flex flex-col items-center justify-center p-6 reveal-data">
      
      {/* 🏛️ The Terminal Card: Now utilizes the centralized classes from your theme */}
      <div className="w-full max-w-md terminal-card relative overflow-hidden shadow-2xl">
        
        {/* Visual Security Indicator */}
        <div className="absolute top-0 left-0 w-full h-[1px] bg-emerald-500/40 shadow-[0_0_15px_var(--accent-glow)] animate-scan" />

        <div className="text-center mb-10">
          <div className="flex justify-center mb-6 text-emerald-500">
            <Cpu size={42} className="animate-pulse" />
          </div>
          <h1 className="text-3xl font-light tracking-tight text-white mb-2 uppercase">
            Access_Gate
          </h1>
          <p className="text-[10px] text-white/30 uppercase tracking-[0.25em] font-mono">
            Node_ID: 8000 // Finify AI Security Protocol
          </p>
        </div>

        <form onSubmit={handleLogin} className="space-y-6">
          <div className="space-y-3">
            <label className="flex items-center gap-2 text-[10px] text-emerald-500 font-bold uppercase tracking-widest ml-1">
              <Terminal size={12} /> Operator_Email
            </label>
            <input
              type="email"
              className="terminal-input"
              placeholder="operator@finify.ai"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
          </div>

          <div className="space-y-3">
            <label className="flex items-center gap-2 text-[10px] text-emerald-500 font-bold uppercase tracking-widest ml-1">
              <Lock size={12} /> Secure_Key
            </label>
            <input
              type="password"
              className="terminal-input"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className={`emerald-btn mt-6 w-full ${loading ? 'opacity-60 cursor-not-allowed' : 'hover:scale-[1.01]'}`}
          >
            {loading ? 'SYNCHRONIZING...' : 'Connect_to_Terminal'}
          </button>
        </form>

        <div className="mt-10 pt-8 border-t border-white/5 text-center">
          <p className="text-[10px] text-white/30 uppercase tracking-[0.25em]">
            Unauthorized node?{' '}
            <Link to="/register" className="text-emerald-500 underline hover:text-emerald-400 transition-colors">
              Initialize_New_Identity
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
